const compactSearch=value=>String(value??'').normalize('NFKC').toLowerCase().replace(/[\s\-_./\\，。；、:：()（）]+/g,'');
function dateParts(value){const match=String(value??'').match(/(?:\d{4}[-/.])?(\d{1,2})[-/.](\d{1,2})/);return match?[Number(match[1]),Number(match[2])]:null}
function fuzzyMatch(record,query){const raw=String(query??'').trim();if(!raw)return true;const compact=compactSearch(JSON.stringify(record)),terms=raw.split(/\s+/).map(compactSearch).filter(Boolean);if(terms.every(term=>compact.includes(term)))return true;const wanted=dateParts(raw),actual=dateParts(dateOf(record));return Boolean(wanted&&actual&&wanted[0]===actual[0]&&wanted[1]===actual[1])}
function latestRecordDate(rows){return rows.reduce((latest,row)=>{const date=new Date(`${dateOf(row)}T00:00:00`);return Number.isNaN(date.valueOf())||date<latest?latest:date},new Date(0))}
function withinDays(row,days,rows){if(!days)return true;const latest=latestRecordDate(rows),date=new Date(`${dateOf(row)}T00:00:00`);return !Number.isNaN(date.valueOf())&&(latest-date)/86400000<days}
const selectedValue=id=>document.getElementById(id)?.value||'all';

