trainingPage=function(){const splits=new Map();state.training.forEach(r=>{const name=String(value(r,'Split')||'Unlabelled');splits.set(name,(splits.get(name)||0)+1)});const top=[...splits.entries()].sort((a,b)=>b[1]-a[1]).slice(0,5);main.innerHTML=`<section class="page training-archive"><div class="training-stage"><div class="training-main">${pageHeader('Training Records','Sessions reduced to their useful signal; full structure stays in the detail view.')}<div class="toolbar"><input class="control search" id="training-search" placeholder="Search split, movement, date or notes..."><select class="control" id="training-order"><option value="recent">Recent first</option><option value="oldest">Oldest first</option></select></div><div id="session-grid" class="session-grid"></div>${pager()}</div><aside class="training-index"><span class="eyebrow">TRAINING INDEX</span><h2>${state.training.length}<small> logged sessions</small></h2><p>A compact map of the most frequent recorded splits.</p><div class="split-index">${top.map(([name,count],i)=>`<button data-training-split="${esc(name)}"><span>0${i+1}</span><strong>${esc(name)}</strong><b>${count}</b></button>`).join('')}</div><div class="training-index-note">OPEN ONLY WHAT YOU NEED</div></aside></div></section>`;renderTraining()}
renderTraining=function(q=$('#training-search')?.value||''){let rows=state.training.filter(r=>fuzzyMatch(r,q));if(selectedValue('training-order')==='oldest')rows=[...rows].reverse();$('#session-grid').innerHTML=rows.slice(0,20).map(r=>{const summary=short(value(r,'Standardized Summary'),92).split(/[,;|]/).filter(Boolean).slice(0,3),stored=value(r,'No.'),fallback=state.training.length-state.training.indexOf(r),sessionNo=stored==='-'?fallback:stored;return `<article class="session session-slip"><div class="session-number">${esc(String(sessionNo).padStart(2,'0'))}</div><div class="rail-head"><h3>${esc(dateOf(r))}</h3><span class="tag volt session-sequence">${esc(sessionNo)}</span></div><p class="session-split">${esc(value(r,'Split'))}</p><div class="session-facts"><span>${summary.length} key movements</span><span>${summary.map(t=>esc(short(t,24))).join(' / ')||'Structured session'}</span></div><p class="session-note">${esc(short(value(r,'Notes'),78))}</p><button class="record-open" data-detail="training" data-index="${state.training.indexOf(r)}">Open structured detail</button></article>`}).join('')||'<p class="empty-note">No training sessions match this search.</p>'}

function movementArtFor(group){const key=String(group||'').toLowerCase();if(/shoulder|肩/.test(key))return'movement-art-arms-core.png';if(/arms?|biceps|triceps|手臂|二头|三头/.test(key))return'movement-art-push.png';if(/back|pull|背/.test(key))return'movement-art-back-v2.png';if(/chest|胸/.test(key))return'movement-art-chest.png';if(/leg|glute|lower|腿|臀/.test(key))return'movement-art-legs-v2.png';return'movement-art-core.png'}
function movementGroupClass(group){const key=String(group||'').toLowerCase();if(/leg|glute|lower|腿|臀/.test(key))return'group-legs';if(/shoulder|肩/.test(key))return'group-shoulders';if(/back|pull|背/.test(key))return'group-back';if(/chest|胸/.test(key))return'group-chest';if(/arms?|biceps|triceps|手臂|二头|三头/.test(key))return'group-arms';return'group-core'}
renderMovementDirectory=function(q=''){const target=$('#movement-list');if(!target)return;const rows=state.movements.filter(m=>fuzzyMatch(m,q)).sort((a,b)=>(state.movementUsage[b.display_name||b.english_name]?.count||0)-(state.movementUsage[a.display_name||a.english_name]?.count||0));const groups=new Map();for(const m of rows){const key=m.muscle_group||'Other';if(!groups.has(key))groups.set(key,[]);groups.get(key).push(m)}const ordered=[...groups.entries()].sort((a,b)=>b[1].reduce((n,m)=>n+(state.movementUsage[m.display_name||m.english_name]?.count||0),0)-a[1].reduce((n,m)=>n+(state.movementUsage[m.display_name||m.english_name]?.count||0),0));target.innerHTML=ordered.map(([group,items],groupIndex)=>`<section class="movement-group group-${groupIndex%3} ${movementGroupClass(group)}"><img class="movement-group-art" src="assets/${movementArtFor(group)}" alt="" aria-hidden="true"><header><span class="group-number">${String(groupIndex+1).padStart(2,'0')}</span><div><h2>${esc(groupLabel(group))}</h2><p>${esc(group)} · ${items.length} movements</p></div></header><div class="movement-mosaic">${items.map((m,i)=>{const name=m.display_name||m.english_name||m.movement_id,count=state.movementUsage[name]?.count||0;return `<button class="movement-tile ${i===0&&count?'tile-lead':count>=4?'tile-wide':'tile-slip'}" data-select-movement="${esc(name)}"><span class="tile-count">${count} sessions</span><strong>${esc(name)}</strong><small>${esc(m.english_name&&m.english_name!==name?m.english_name:groupLabel(group))}</small><em>Open trajectory →</em></button>`}).join('')}</div></section>`).join('')||'<p class="empty-note">No matching movements.</p>';const count=$('.result-count');if(count)count.textContent=`${rows.length} movements`}
loadMovementFocus=async function(name){state.movementSelection=name;main.innerHTML=`<section class="page movement-detail-page"><button class="movement-back" data-movement-index>← Movement Index</button><div id="movement-focus"><div class="loading-page"><i></i><p>Loading recorded history…</p></div></div></section>`;const focus=$('#movement-focus');try{let payload=state.movementUsage[name]?.payload;if(!payload)payload=await api(`/api/movement-history?name=${encodeURIComponent(name)}&limit=50`);state.movementHistory=payload;const movement=payload.movement||{},history=payload.history||[],latest=history[0],earliest=history[history.length-1],art=movementArtFor(movement.muscle_group);focus.innerHTML=`<div class="movement-detail-compact"><img src="assets/${art}" alt="" aria-hidden="true"><div><span class="eyebrow">RECORDED TRAJECTORY</span><h1>${esc(movement.display_name||name)}</h1><p>${esc(movement.english_name||movement.muscle_group||'Recorded movement')}</p></div><div class="movement-detail-stats"><span><b>${history.length}</b> sessions</span><span><b>${esc(latest?.date||'—')}</b> latest</span><span><b>${esc(earliest?.date||'—')}</b> first</span></div></div><div class="trajectory-heading"><span class="eyebrow">PROGRESSION / NEWEST FIRST</span><h2>Training trajectory</h2><p>每次训练的负重、次数、组数和备注按时间展开。</p></div><div class="trajectory"><div class="trajectory-line"></div>${history.map((r,i)=>`<article class="trajectory-entry ${i===0?'is-latest':''}"><div class="trajectory-marker">${String(i+1).padStart(2,'0')}</div><div class="history-date"><strong>${esc(r.date||'—')}</strong><small>Day ${esc(r.training_day??'—')} · Ex ${esc(r.order??'—')}</small></div><div class="history-content"><h3>${esc((r.sets_lines||[]).join(' · ')||'Recorded without structured sets')}</h3>${r.notes?`<p>${esc(r.notes)}</p>`:''}</div></article>`).join('')||'<div class="empty-copy"><h3>No history yet</h3><p>This movement exists in the dictionary but has no recorded sessions.</p></div>'}</div>`}catch{focus.innerHTML='<div class="empty-copy"><h3>History unavailable</h3><p>The local read-only service could not load this movement.</p></div>'}}

function movementRecordMetrics(record){let maxLoad=0,volume=0,totalReps=0;for(const line of record.sets_lines||[]){const pattern=/(\d+(?:\.\d+)?)\s*(?:kg)?\s*[×x*]\s*(\d+)\s*[×x*]\s*(\d+)/gi;let match;while((match=pattern.exec(line))){const load=Number(match[1]),reps=Number(match[2]),sets=Number(match[3]);maxLoad=Math.max(maxLoad,load);volume+=load*reps*sets;totalReps+=reps*sets}if(/自重|body\s*weight|\bbw\b/i.test(line)){const body=line.match(/[×x*]\s*(\d+)\s*[×x*]\s*(\d+)/i);if(body){const reps=Number(body[1]),sets=Number(body[2]);totalReps+=reps*sets;volume+=reps*sets}}}return {maxLoad,volume,totalReps}}
function movementProgressChart(history){const records=history.slice(0,8).reverse().map(record=>({...record,...movementRecordMetrics(record)}));if(!records.length)return'';const useLoad=records.some(record=>record.maxLoad>0),values=records.map(record=>useLoad?record.maxLoad:record.totalReps),volumes=records.map(record=>record.volume),maxValue=Math.max(...values,1),maxVolume=Math.max(...volumes,1),left=48,right=682,width=right-left,step=records.length>1?width/(records.length-1):0;const points=records.map((record,index)=>`${left+index*step},${145-(values[index]/maxValue)*92}`).join(' ');const bars=records.map((record,index)=>{const height=(volumes[index]/maxVolume)*70,x=left+index*step-12;return `<rect x="${x}" y="${160-height}" width="24" height="${height}" rx="4"></rect>`}).join('');const dots=records.map((record,index)=>`<circle cx="${left+index*step}" cy="${145-(values[index]/maxValue)*92}" r="5"></circle>`).join('');const labels=records.map((record,index)=>`<text x="${left+index*step}" y="194" text-anchor="middle">${esc(String(record.date||'').slice(5))}</text>`).join('');const latest=values.at(-1)||0,previous=values.at(-2)||latest,delta=Math.round((latest-previous)*10)/10;return `<section class="movement-progress-panel"><div class="progress-copy"><span class="eyebrow">RECENT 8 / VISUAL SUMMARY</span><h2>Recent change</h2><p>${useLoad?'折线为最高负重，柱形为估算训练容量。':'自重动作以总次数趋势显示，柱形同步表达训练工作量。'}</p></div><div class="progress-signal"><span>Latest</span><strong>${latest}${useLoad?' kg':' reps'}</strong><small class="${delta>0?'up':delta<0?'down':''}">${delta>0?'+':''}${delta} vs previous</small></div><svg class="progress-chart" viewBox="0 0 730 220" role="img" aria-label="Recent movement progression"><g class="chart-grid"><line x1="48" y1="53" x2="682" y2="53"></line><line x1="48" y1="99" x2="682" y2="99"></line><line x1="48" y1="145" x2="682" y2="145"></line></g><g class="volume-bars">${bars}</g><polyline class="load-line" points="${points}"></polyline><g class="load-dots">${dots}</g><g class="chart-labels">${labels}</g></svg></section>`}
loadMovementFocus=async function(name){state.movementSelection=name;main.innerHTML=`<section class="page movement-detail-page"><button class="movement-back" data-movement-index>← Movement Index</button><div id="movement-focus"><div class="loading-page"><i></i><p>Loading recorded history…</p></div></div></section>`;const focus=$('#movement-focus');try{let payload=state.movementUsage[name]?.payload;if(!payload)payload=await api(`/api/movement-history?name=${encodeURIComponent(name)}&limit=50`);state.movementHistory=payload;const movement=payload.movement||{},history=payload.history||[],latest=history[0],earliest=history[history.length-1],art=movementArtFor(movement.muscle_group),display=movement.display_name||name,longClass=String(display).length>5?'is-long':'';focus.innerHTML=`<div class="movement-detail-compact ${longClass}"><img class="movement-detail-art" src="assets/${art}" alt="" aria-hidden="true"><div class="movement-detail-title"><span class="eyebrow">RECORDED TRAJECTORY</span><h1>${esc(display)}</h1><p>${esc(movement.english_name||movement.muscle_group||'Recorded movement')}</p></div><div class="movement-detail-stats"><span><b>${history.length}</b> sessions</span><span><b>${esc(latest?.date||'—')}</b> latest</span><span><b>${esc(earliest?.date||'—')}</b> first</span></div></div>${movementProgressChart(history)}<div class="trajectory-heading"><span class="eyebrow">PROGRESSION / NEWEST FIRST</span><h2>Training trajectory</h2><p>每次训练的负重、次数、组数和备注按时间展开。</p></div><div class="trajectory"><div class="trajectory-line"></div>${history.map((r,i)=>`<article class="trajectory-entry ${i===0?'is-latest':''}"><div class="trajectory-marker">${String(i+1).padStart(2,'0')}</div><div class="history-date"><strong>${esc(r.date||'—')}</strong><small>Day ${esc(r.training_day??'—')} · Ex ${esc(r.order??'—')}</small></div><div class="history-content"><h3>${esc((r.sets_lines||[]).join(' · ')||'Recorded without structured sets')}</h3>${r.notes?`<p>${esc(r.notes)}</p>`:''}</div></article>`).join('')||'<div class="empty-copy"><h3>No history yet</h3><p>This movement exists in the dictionary but has no recorded sessions.</p></div>'}</div>`}catch{focus.innerHTML='<div class="empty-copy"><h3>History unavailable</h3><p>The local read-only service could not load this movement.</p></div>'}}

async function postApi(path,payload){const response=await fetch(path,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});const data=await response.json().catch(()=>({error:'Invalid local service response.'}));if(!response.ok){const error=Error(data.error||`Request failed (${response.status})`);error.status=response.status;error.payload=data;throw error}return data}
const recordEditFields={body:['Date','Weight (kg)','Bowel Movement','Training','Cardio','Notes'],diet:['Date','Calories (kcal)','Protein (g)','Carbs (g)','Fat (g)','Food Summary','Notes'],training:['Date','Split','Raw Record','Standardized Summary','Notes']};
const longRecordFields=new Set(['Food Summary','Raw Record','Standardized Summary','Notes']);
function realRecordDetail(kind,index){const rows={body:state.body,diet:state.diet,training:state.training},record=rows[kind]?.[index];if(!record)return;const fields=recordEditFields[kind]||[];const content=`<form id="record-edit-form" class="record-edit-form" data-record-type="${kind}" data-record-id="${esc(record.id||'')}">${fields.map(field=>`<label class="${longRecordFields.has(field)?'is-wide':''}"><span>${esc(field)}</span>${longRecordFields.has(field)?`<textarea name="${esc(field)}" rows="${field==='Notes'?3:5}">${esc(record[field]??'')}</textarea>`:`<input name="${esc(field)}" value="${esc(record[field]??'')}" ${field==='Date'?'type="date"':''}>`}</label>`).join('')}<p class="record-edit-note">保存前自动创建成对备份。未显示字段和每日原始输入保持不变。</p></form>`;modal(`${kind[0].toUpperCase()+kind.slice(1)} Record`,content,{light:kind==='diet',actions:`<button class="btn" data-close>取消</button><button class="btn btn-primary" data-record-save>保存修改</button>`})}
detail=realRecordDetail;
async function saveRecordEdit(){const form=$('#record-edit-form');if(!form)return;const values=Object.fromEntries(new FormData(form).entries()),button=$('[data-record-save]');button.disabled=true;try{await postApi('/api/record/update',{record_type:form.dataset.recordType,record_id:form.dataset.recordId,values});root.innerHTML='';await refreshWebState();navigate(form.dataset.recordType);showToast('记录已安全更新。')}catch(error){button.disabled=false;showToast(error.message||'记录保存失败。')}}
function movementHistoryEditor(index){const movement=state.movementHistory?.movement,record=state.movementHistory?.history?.[index];if(!movement||!record)return;const cardio=record.cardio||{};modal(`编辑动作记录 · ${movement.display_name}`,`<form id="movement-history-form" class="record-edit-form" data-movement-id="${esc(movement.movement_id)}" data-history-id="${esc(record.id||'')}"><label><span>日期（只读）</span><input value="${esc(record.date||'')}" disabled></label><label><span>动作顺序</span><input name="order" value="${esc(record.order??'')}"></label><label class="is-wide"><span>组数（每行：重量 × 次数 × 组数）</span><textarea name="sets_text" rows="5">${esc((record.sets_lines||[]).join('\n'))}</textarea></label><label><span>有氧分钟</span><input name="duration_minutes" value="${esc(cardio.duration_minutes??'')}"></label><label><span>坡度</span><input name="incline" value="${esc(cardio.incline??'')}"></label><label><span>速度</span><input name="speed" value="${esc(cardio.speed??'')}"></label><label><span>心率</span><input name="heart_rate" value="${esc(cardio.heart_rate??'')}"></label><label class="is-wide"><span>动作备注</span><textarea name="notes" rows="3">${esc(record.notes||'')}</textarea></label><label class="is-wide"><span>原始动作细节</span><textarea name="raw" rows="3">${esc(record.raw||'')}</textarea></label></form>`,{light:true,actions:`<button class="btn" data-close>取消</button><button class="btn btn-primary" data-movement-history-save>保存动作记录</button>`})}
async function saveMovementHistory(){const form=$('#movement-history-form');if(!form)return;const values=Object.fromEntries(new FormData(form).entries()),button=$('[data-movement-history-save]');button.disabled=true;try{await postApi('/api/movement-history/update',{movement_id:form.dataset.movementId,history_id:form.dataset.historyId,values});root.innerHTML='';state.usageLoaded=false;state.movementUsage={};await refreshWebState();await loadMovementFocus(state.movementSelection);showToast('动作成长记录已安全更新。')}catch(error){button.disabled=false;showToast(error.message||'动作记录保存失败。')}}
const baseMovementFocus=loadMovementFocus;
loadMovementFocus=async function(name){await baseMovementFocus(name);$$('.trajectory-entry').forEach((entry,index)=>{const button=document.createElement('button');button.className='trajectory-edit';button.dataset.movementHistoryEdit=String(index);button.textContent='Edit record';entry.appendChild(button)})};
const reviewValue=(path,fallback='')=>path.split('.').reduce((value,key)=>value?.[key],state.reviewPayload?.review)??fallback;
function setReviewValue(path,value){const parts=path.split('.');let target=state.reviewPayload.review;parts.slice(0,-1).forEach(key=>{target=target[key]??={}});target[parts.at(-1)]=value}
function reviewMetric(label,value,unit=''){return `<div class="review-metric"><span>${label}</span><strong>${esc(value??'缺失')}</strong>${unit?`<small>${unit}</small>`:''}</div>`}
function reviewInput(label,path,{type='text',wide=false,rows=1}={}){const value=reviewValue(path,'');return `<label class="review-field ${wide?'is-wide':''}"><span>${label}</span>${rows>1?`<textarea rows="${rows}" data-review-field="${path}">${esc(value)}</textarea>`:`<input type="${type}" value="${esc(value)}" data-review-field="${path}">`}</label>`}
function reviewSetText(item){if(typeof item!=='object'||item===null)return String(item||'');const load=item.weight_text||item.load||item.weight_label||(Number(item.weight)>0?`${item.weight}kg`:'自重');return `${load} × ${item.reps??'-'} × ${item.sets??1}`}
function movementReviewRow(movement,index,options){const known=movement.movement_id,action=movement._review_action||(known?'use':'add'),inactive=known&&movement._matched_active===false;return `<article class="review-movement" data-movement-row="${index}"><span class="review-order">${String(movement.order??index+1).padStart(2,'0')}</span><div class="review-movement-copy"><input class="movement-name-input" value="${esc(movement.display_name||movement.name)}" data-movement-name="${index}" aria-label="动作名称"><small>${esc(movement.name)} · ${(movement.sets||[]).length} 组</small><p>${esc((movement.sets||[]).map(reviewSetText).join(' · ')||'未识别到结构化组数')}</p></div><label class="review-note"><span>动作备注</span><input value="${esc(movement.notes||'')}" data-movement-note="${index}"></label><div class="review-decision"><span class="review-status ${known?'is-existing':'is-new'}">${inactive?'已停用 · 仍会记录':known?'已有动作':'新动作'}</span><select data-movement-action="${index}"><option value="use" ${action==='use'?'selected':''}>采用当前识别</option><option value="add" ${action==='add'?'selected':''}>加入动作词典</option><option value="map" ${action==='map'?'selected':''}>映射到已有动作</option><option value="skip" ${action==='skip'?'selected':''}>仅保留原始记录</option></select><select data-movement-map="${index}" ${action==='map'?'':'disabled'}><option value="">选择已有动作…</option>${options.map(option=>`<option value="${esc(option.movement_id)}" ${movement._mapped_movement_id===option.movement_id?'selected':''}>${esc(option.display_name)}${option.english_name?` / ${esc(option.english_name)}`:''}</option>`).join('')}</select></div></article>`}
reviewPage=function(payload){state.reviewPayload=payload;state.view='review';$$('.nav-item').forEach(button=>button.classList.toggle('is-active',button.dataset.view==='quick'));const review=payload.review,summary=payload.summary||{},warnings=payload.warnings||[],duplicates=payload.duplicates||{},duplicateCount=Object.values(duplicates).reduce((sum,value)=>sum+Number(value||0),0);main.innerHTML=`<section class="review-scroll-page"><aside class="review-index"><span class="eyebrow">REVIEW INDEX</span>${[['01','Summary'],['02','Body'],['03','Diet'],['04','Training'],['05','Movements'],['06','Warnings']].map(item=>`<a href="#review-${item[1].toLowerCase()}"><b>${item[0]}</b>${item[1]}</a>`).join('')}<p>RAW PRESERVED<br>LOCAL / PRIVATE</p></aside><div class="review-document"><header class="review-document-head"><div><span class="eyebrow">PARSE & REVIEW</span><h1>Review before save.</h1><p>检查结构化结果。原始输入将完整保留。</p></div><button class="home-text-link" data-review-back>← 返回修改</button></header><section class="review-summary-paper" id="review-summary"><div class="review-summary-date"><span>ENTRY DATE</span><strong>${esc(summary.date||'缺失')}</strong></div>${reviewMetric('体重',summary.weight,'kg')}${reviewMetric('排便',summary.bowel_movement||'缺失')}${reviewMetric('热量',summary.calories,'kcal')}${reviewMetric('蛋白质',summary.protein,'g')}${reviewMetric('碳水',summary.carbs,'g')}${reviewMetric('脂肪',summary.fat,'g')}${reviewMetric('训练',summary.training||'缺失')}${reviewMetric('动作',summary.movement_count,'个')}${reviewMetric('有氧',summary.cardio||'缺失')}</section><section class="review-ledger-section" id="review-body"><header><span>02</span><h2>Body <small>身体</small></h2></header><div class="review-fields">${reviewInput('日期','date')}${reviewInput('体重 (kg)','body.weight',{type:'number'})}${reviewInput('排便','body.bowel_movement')}${reviewInput('训练部位','body.training_summary')}${reviewInput('有氧','body.cardio_summary',{wide:true})}${reviewInput('身体备注','body.notes',{wide:true,rows:2})}</div></section><section class="review-ledger-section" id="review-diet"><header><span>03</span><h2>Diet <small>饮食</small></h2></header><div class="review-fields review-macro-fields">${reviewInput('热量 (kcal)','diet.calories',{type:'number'})}${reviewInput('蛋白质 (g)','diet.protein',{type:'number'})}${reviewInput('碳水 (g)','diet.carbs',{type:'number'})}${reviewInput('脂肪 (g)','diet.fat',{type:'number'})}${reviewInput('饮食记录','diet.food_summary',{wide:true,rows:4})}${reviewInput('饮食备注','diet.notes',{wide:true,rows:2})}</div></section><section class="review-ledger-section" id="review-training"><header><span>04</span><h2>Training <small>训练</small></h2></header><div class="review-fields">${reviewInput('训练部位','training.split')}${reviewInput('标准摘要','training.standardized_summary',{wide:true,rows:2})}${reviewInput('训练备注','training.notes',{wide:true,rows:2})}</div></section><section class="review-ledger-section review-movements-section" id="review-movements"><header><span>05</span><h2>Movements <small>动作识别 · ${review.training?.movements?.length||0}</small></h2></header><div class="review-movement-list">${(review.training?.movements||[]).map((movement,index)=>movementReviewRow(movement,index,payload.mapping_options||[])).join('')||'<p class="empty-note">没有识别到训练动作。</p>'}</div></section><section class="review-ledger-section review-warning-section" id="review-warnings"><header><span>06</span><h2>Warnings <small>保存前检查</small></h2></header><div class="review-warning-list">${warnings.map(warning=>`<div class="review-warning ${esc(warning.severity)}"><b>${esc(warning.severity)}</b><span>${esc(warning.message)}</span></div>`).join('')||'<p class="review-clear">未发现明显问题。</p>'}</div>${duplicateCount?`<label class="duplicate-choice"><span>该日期已有 ${duplicateCount} 类记录，请选择保存方式</span><select id="review-save-mode"><option value="">保存时选择…</option><option value="overwrite">覆盖当天 Body / Diet / Training</option><option value="append_training">追加为同日第二次训练</option></select></label>`:''}</section></div><footer class="review-action-bar"><button class="btn btn-light" data-review-cancel>取消</button><button class="btn btn-light" data-review-back>← 返回修改</button><button class="btn btn-primary" data-review-save>确认并保存</button><small>原始文本保留 · 保存前自动备份</small></footer></section>`;window.scrollTo(0,0)}
const baseReviewPage=reviewPage;
reviewPage=function(payload){baseReviewPage(payload);const documentBody=$('.review-document'),head=$('.review-document-head'),movements=$('#review-movements'),index=$('.review-index');if(documentBody&&head&&movements){movements.classList.add('is-primary-review');head.insertAdjacentElement('afterend',movements)}if(index){const movementLink=index.querySelector('a[href="#review-movements"]'),firstLink=index.querySelector('a');if(movementLink&&firstLink)index.insertBefore(movementLink,firstLink);index.querySelectorAll('a').forEach((link,position)=>{const number=link.querySelector('b');if(number)number.textContent=String(position+1).padStart(2,'0')})}};
function collectReviewForm(){if(!state.reviewPayload)return null;$$('[data-review-field]').forEach(input=>setReviewValue(input.dataset.reviewField,input.type==='number'?(input.value===''?null:Number(input.value)):input.value));const movements=state.reviewPayload.review.training?.movements||[];movements.forEach((movement,index)=>{movement.display_name=$(`[data-movement-name="${index}"]`)?.value.trim()||movement.name;movement.notes=$(`[data-movement-note="${index}"]`)?.value.trim()||'';movement._review_action=$(`[data-movement-action="${index}"]`)?.value||'use';movement._mapped_movement_id=$(`[data-movement-map="${index}"]`)?.value||''});return state.reviewPayload.review}
async function parseWebEntry(){const raw=$('#raw-entry')?.value.trim();if(!raw){showToast('请先输入每日记录。');return}state.draftRaw=raw;showToast('正在解析…');try{reviewPage(await postApi('/api/parse',{raw}))}catch(error){showToast(error.message||'解析失败。')}}
async function refreshWebState(){[state.today,state.recent,state.body,state.diet,state.training,state.movements]=await Promise.all([api('/api/today'),api('/api/recent?limit=5'),api('/api/body?limit=100'),api('/api/diet?limit=100'),api('/api/training?limit=100'),api('/api/movements?limit=100')])}
async function saveWebReview(){const review=collectReviewForm();if(!review)return;const mode=$('#review-save-mode')?.value||null;const button=$('[data-review-save]');button.disabled=true;button.textContent='正在保存…';try{const result=await postApi('/api/save',{review_id:state.reviewPayload.review_id,review,save_mode:mode});state.reviewPayload=null;state.draftRaw='';await refreshWebState();navigate('quick');showToast(`${result.date} 已安全保存。`)}catch(error){button.disabled=false;button.textContent='确认并保存';if(error.status===409){showToast('该日期已有记录，请选择覆盖或追加训练。');$('#review-save-mode')?.focus()}else showToast(error.message||'保存失败，原文件保持不变。')}}
const writableQuickPage=quickPage;
quickPage=function(){writableQuickPage();const phase=$('.phase');if(phase)phase.textContent='解析后进入 Review；确认保存时自动创建本地备份。';const textarea=$('#raw-entry');if(textarea&&state.draftRaw)textarea.value=state.draftRaw;const undo=$('[data-mock^="Undo"]');if(undo){undo.disabled=true;undo.title='Undo 仍由本地桌面端管理'}}

function dictionaryPage(){main.innerHTML=`<section class="page dictionary-page"><header class="dictionary-hero"><div><span class="eyebrow">07 / CONTROLLED VOCABULARY</span><h1>Movement<br>Dictionary</h1><p>管理标准名称、别名和训练部位。停用只会隐藏成长视图，仍可继续识别并记录。</p></div><button class="btn btn-primary" data-dictionary-new>+ 新建动作</button></header><div class="dictionary-toolbar"><input id="dictionary-search" class="control search" placeholder="搜索名称、英文名、别名或 ID…"><select id="dictionary-status" class="control"><option value="all">全部状态</option><option value="active">仅启用</option><option value="inactive">仅停用</option></select><span id="dictionary-count" class="result-count">正在读取…</span></div><div class="dictionary-sheet"><div class="dictionary-sheet-head"><span>状态</span><span>标准动作</span><span>训练部位</span><span>别名</span><span>历史</span><span>操作</span></div><div id="dictionary-rows"><div class="loading-page"><i></i><p>Reading movement dictionary…</p></div></div></div></section>`;loadDictionary()}

async function loadDictionary(){try{state.dictionary=await api('/api/dictionary');renderDictionary()}catch(error){const target=$('#dictionary-rows');if(target)target.innerHTML=`<div class="empty-copy"><h3>词典读取失败</h3><p>${esc(error.message)}</p></div>`}}

function renderDictionary(){const target=$('#dictionary-rows');if(!target)return;const query=($('#dictionary-search')?.value||'').trim().toLowerCase(),status=$('#dictionary-status')?.value||'all';const rows=state.dictionary.filter(item=>{const active=item.active!==false;if(status==='active'&&!active)return false;if(status==='inactive'&&active)return false;return !query||JSON.stringify(item).toLowerCase().includes(query)});target.innerHTML=rows.map(item=>{const active=item.active!==false,aliases=item.aliases||[];return `<article class="dictionary-row ${active?'':'is-inactive'}"><span class="dictionary-state ${active?'is-active':'is-inactive'}"><i></i>${active?'启用':'停用'}</span><div class="dictionary-name"><strong>${esc(item.display_name||'未命名')}</strong><small>${esc(item.english_name||item.movement_id||'')}</small><em>${esc(item.movement_id||'')}</em></div><span>${esc(groupLabel(item.muscle_group||'Unclassified'))}<small>${esc(item.category||'')}</small></span><div class="dictionary-aliases">${aliases.slice(0,4).map(alias=>`<b>${esc(alias)}</b>`).join('')}${aliases.length>4?`<small>+${aliases.length-4}</small>`:''}</div><span class="dictionary-history"><strong>${Number(item.history_count||0)}</strong><small>条记录</small></span><div class="dictionary-actions"><button class="home-text-link" data-dictionary-edit="${esc(item.movement_id)}">编辑</button><button class="home-text-link" data-dictionary-toggle="${esc(item.movement_id)}">${active?'停用':'启用'}</button><button class="home-text-link danger" data-dictionary-delete="${esc(item.movement_id)}">删除</button></div></article>`}).join('')||'<div class="empty-copy"><h3>没有匹配动作</h3><p>调整搜索词或状态筛选。</p></div>';const count=$('#dictionary-count');if(count)count.textContent=`${rows.length} / ${state.dictionary.length} movements`}

function dictionaryForm(item={}){const aliases=(item.aliases||[]).join('\n');return `<form id="dictionary-form" class="dictionary-form"><input type="hidden" name="movement_id" value="${esc(item.movement_id||'')}"><label><span>中文标准名 *</span><input name="display_name" value="${esc(item.display_name||'')}" required></label><label><span>英文名称</span><input name="english_name" value="${esc(item.english_name||'')}"></label><label><span>训练部位</span><input name="muscle_group" value="${esc(item.muscle_group||'Unclassified')}" placeholder="Chest / Back / Legs / Shoulder…"></label><label><span>类别</span><input name="category" value="${esc(item.category||'Strength')}"></label><label><span>器械</span><input name="equipment" value="${esc(item.equipment||'')}"></label><label class="is-wide"><span>别名（每行一个）</span><textarea name="aliases" rows="6">${esc(aliases)}</textarea><small>更改后会扫描历史 CUSTOM 动作和曾跳过的原始记录并尝试归并。</small></label><label class="is-wide"><span>备注</span><textarea name="notes" rows="3">${esc(item.notes||'')}</textarea></label></form>`}

function openDictionaryEditor(movementId=''){const item=state.dictionary.find(row=>row.movement_id===movementId)||{};modal(movementId?'编辑动作词典':'新建动作词典',dictionaryForm(item),{light:true,actions:`<button class="btn" data-close>取消</button><button class="btn btn-primary" data-dictionary-save="${esc(movementId)}">保存词典</button>`})}

function collectDictionaryForm(){const form=$('#dictionary-form');if(!form)return null;const data=Object.fromEntries(new FormData(form).entries());data.aliases=String(data.aliases||'').split(/\r?\n|,|，|;|；/).map(value=>value.trim()).filter(Boolean);return data}

async function saveDictionaryForm(movementId){const definition=collectDictionaryForm();if(!definition?.display_name?.trim()){showToast('中文标准名不能为空。');return}const button=$('[data-dictionary-save]');button.disabled=true;try{const result=await postApi(movementId?'/api/dictionary/update':'/api/dictionary/create',movementId?{movement_id:movementId,definition}:definition);root.innerHTML='';state.usageLoaded=false;await Promise.all([loadDictionary(),refreshWebState()]);renderDictionary();showToast(`动作词典已保存；归并 ${Number(result.reconciliation?.merged_history||0)+Number(result.reconciliation?.restored_skipped||0)} 条历史。`)}catch(error){button.disabled=false;showToast(error.message||'词典保存失败。')}}

async function toggleDictionaryEntry(movementId){const item=state.dictionary.find(row=>row.movement_id===movementId);if(!item)return;try{await postApi('/api/dictionary/active',{movement_id:movementId,active:item.active===false});state.usageLoaded=false;await Promise.all([loadDictionary(),refreshWebState()]);renderDictionary();showToast(item.active===false?'动作已启用。':'动作已停用；历史仍会保留并继续记录。')}catch(error){showToast(error.message||'状态更新失败。')}}

function confirmDictionaryDelete(movementId){const item=state.dictionary.find(row=>row.movement_id===movementId);if(!item)return;modal('删除动作词典',`<div class="dictionary-delete-warning"><span class="eyebrow">DESTRUCTIVE ACTION</span><p>将删除 <strong>${esc(item.display_name)}</strong> 的词典项及 <strong>${Number(item.history_count||0)}</strong> 条结构化动作历史。每日原始输入不会删除。</p><label class="field"><span>输入“${esc(item.display_name)}”确认</span><input id="dictionary-delete-confirm" autocomplete="off"></label></div>`,{light:true,actions:`<button class="btn" data-close>取消</button><button class="btn btn-danger" data-dictionary-delete-confirm="${esc(movementId)}">确认删除</button>`})}

async function deleteDictionaryEntry(movementId){const confirmation=$('#dictionary-delete-confirm')?.value||'';try{const result=await postApi('/api/dictionary/delete',{movement_id:movementId,confirmation});root.innerHTML='';state.usageLoaded=false;await Promise.all([loadDictionary(),refreshWebState()]);renderDictionary();showToast(`已删除 ${result.display_name} 及 ${result.deleted_history} 条结构化历史。`)}catch(error){showToast(error.message||'删除失败。')}}

renderDictionary=function(){const target=$('#dictionary-rows');if(!target)return;const query=($('#dictionary-search')?.value||'').trim().toLowerCase(),status=$('#dictionary-status')?.value||'all';const rows=state.dictionary.filter(item=>{const active=item.active!==false;if(status==='active'&&!active)return false;if(status==='inactive'&&active)return false;return !query||JSON.stringify(item).toLowerCase().includes(query)});const head=$('.dictionary-sheet-head');if(head)head.innerHTML='<span>状态</span><span>标准动作</span><span>训练部位</span><span>历史</span><span>操作</span>';target.innerHTML=rows.map(item=>{const active=item.active!==false;return `<article class="dictionary-row dictionary-row-compact ${active?'':'is-inactive'}"><span class="dictionary-state ${active?'is-active':'is-inactive'}"><i></i>${active?'启用':'停用'}</span><div class="dictionary-name"><strong>${esc(item.display_name||'未命名')}</strong><small>${esc(item.english_name||item.movement_id||'')}</small></div><span class="dictionary-group">${esc(groupLabel(item.muscle_group||'Unclassified'))}</span><span class="dictionary-history"><strong>${Number(item.history_count||0)}</strong><small>条</small></span><div class="dictionary-actions dictionary-icon-actions"><button title="编辑动作" aria-label="编辑 ${esc(item.display_name)}" data-dictionary-edit="${esc(item.movement_id)}"><b>✎</b><span>编辑</span></button><button title="${active?'停用动作':'启用动作'}" aria-label="${active?'停用':'启用'} ${esc(item.display_name)}" data-dictionary-toggle="${esc(item.movement_id)}"><b>${active?'◐':'●'}</b><span>${active?'停用':'启用'}</span></button><button class="danger" title="删除动作" aria-label="删除 ${esc(item.display_name)}" data-dictionary-delete="${esc(item.movement_id)}"><b>×</b><span>删除</span></button></div></article>`}).join('')||'<div class="empty-copy"><h3>没有匹配动作</h3><p>调整搜索词或状态筛选。</p></div>';const count=$('#dictionary-count');if(count)count.textContent=`${rows.length} / ${state.dictionary.length} movements`};

async function load(){try{[state.today,state.recent,state.body,state.diet,state.training,state.movements]=await Promise.all([api('/api/today'),api('/api/recent?limit=5'),api('/api/body?limit=100'),api('/api/diet?limit=100'),api('/api/training?limit=100'),api('/api/movements?limit=100')]);navigate(location.hash.slice(1)||'home')}catch(e){main.innerHTML=`<div class="loading-page"><h2>Local data service unavailable</h2><p>${esc(e.message)}</p></div>`}}
function navigate(v){state.view=v;location.hash=v;$$('.nav-item').forEach(b=>b.classList.toggle('is-active',b.dataset.view===v));({home:homePage,quick:quickPage,body:bodyPage,diet:dietPage,training:trainingPage,movements:movementPage,checks:checksPage,dictionary:dictionaryPage,export:analysisExportPage}[v]||homePage)();window.scrollTo(0,0)}
document.addEventListener('click',event=>{const target=event.target.closest('button,a');if(!target)return;if(target.id==='parse'){event.preventDefault();event.stopImmediatePropagation();parseWebEntry();return}if(target.dataset.reviewSave!==undefined){event.preventDefault();event.stopImmediatePropagation();saveWebReview();return}if(target.dataset.reviewBack!==undefined){event.preventDefault();event.stopImmediatePropagation();navigate('quick');return}if(target.dataset.reviewCancel!==undefined){event.preventDefault();event.stopImmediatePropagation();state.reviewPayload=null;state.draftRaw='';navigate('quick');return}if(target.matches('.review-index a')){event.preventDefault();event.stopImmediatePropagation();document.querySelector(target.getAttribute('href'))?.scrollIntoView({behavior:'smooth',block:'start'})}},true);
document.addEventListener('change',event=>{const action=event.target.closest('[data-movement-action]');if(!action)return;const mapping=$(`[data-movement-map="${action.dataset.movementAction}"]`);if(mapping)mapping.disabled=action.value!=='map'});
document.addEventListener('click',e=>{const b=e.target.closest('button,[data-detail],[data-movement],[data-issue]');if(!b)return;if(b.dataset.view)navigate(b.dataset.view);if(b.dataset.go)navigate(b.dataset.go);if(b.dataset.close!==undefined){root.innerHTML='';return}if(b.dataset.mock)showToast(b.dataset.mock);if(b.dataset.record)recordDetail(b.dataset.record);if(b.dataset.detail)detail(b.dataset.detail,Number(b.dataset.index));if(b.dataset.movementIndex!==undefined)movementPage();else if(b.dataset.selectMovement)loadMovementFocus(b.dataset.selectMovement);else if(b.dataset.movement)movementDetail(b.dataset.movement);if(b.dataset.issue!==undefined)modal('Issue detail',`<span class="severity ${issues[b.dataset.issue][0].toLowerCase()}">${issues[b.dataset.issue][0]}</span><div class="detail-list"><div class="detail-row"><label>Date</label><div>${issues[b.dataset.issue][1]}</div></div><div class="detail-row"><label>Area</label><div>${issues[b.dataset.issue][2]}</div></div><div class="detail-row"><label>Issue</label><div>${issues[b.dataset.issue][3]}</div></div></div>`,{actions:'<button class="btn btn-primary" data-mock="Open action is a UI preview.">Take action →</button>'});if(b.id==='parse')reviewPage($('#raw-entry').value);if(b.dataset.back!==undefined)navigate('quick');if(b.dataset.duplicate!==undefined)duplicate();if(b.dataset.approval!==undefined)approval();if(b.dataset.drawer)drawer(b.dataset.drawer)});
document.addEventListener('input',e=>{if(e.target.id==='body-search')renderBodyRows(e.target.value);if(e.target.id==='diet-search')renderDietRows(e.target.value);if(e.target.id==='training-search')renderTraining(e.target.value);if(e.target.id==='movement-search')renderMovementDirectory(e.target.value)});
document.addEventListener('change',e=>{if(['body-time','body-training','body-bowel','body-cardio'].includes(e.target.id))renderBodyRows();if(e.target.id==='diet-meal')renderDietRows();if(e.target.id==='training-order')renderTraining()});
document.addEventListener('click',e=>{const split=e.target.closest('[data-training-split]');if(!split)return;const search=$('#training-search');if(search){search.value=split.dataset.trainingSplit;renderTraining(search.value);search.focus()}});
document.addEventListener('click',e=>{const filter=e.target.closest('[data-check-filter]');if(!filter)return;const selected=filter.dataset.checkFilter;$$('[data-check-filter]').forEach(button=>{const active=button===filter;button.classList.toggle('btn-primary',active);button.classList.toggle('is-selected',active)});let visible=0;$$('#main tr[data-severity]').forEach(row=>{const show=selected==='all'||row.dataset.severity===selected;row.hidden=!show;if(show)visible++});const status=$('.records-status');if(status)status.textContent=`${visible} local ${visible===1?'issue':'issues'} shown`});
document.addEventListener('click',e=>{const trigger=e.target.closest('[data-open-issue]');if(!trigger)return;e.stopPropagation();const issue=issues[Number(trigger.dataset.openIssue)];modal('问题详情',`<span class="severity ${issue[0].toLowerCase()}">${issue[0]}</span><div class="detail-list"><div class="detail-row"><label>日期</label><div>${issue[1]}</div></div><div class="detail-row"><label>区域</label><div>${issue[2]}</div></div><div class="detail-row"><label>具体问题</label><div>${issue[3]}</div></div><div class="detail-row"><label>建议处理</label><div>${issue[4]}</div></div></div>`,{actions:'<button class="btn btn-primary" data-mock="正式修改请在本地桌面版完成。">前往处理 →</button>'})});
document.addEventListener('input',event=>{if(event.target.id==='dictionary-search')renderDictionary()});
document.addEventListener('change',event=>{if(event.target.id==='dictionary-status')renderDictionary()});
document.addEventListener('click',event=>{const target=event.target.closest('[data-dictionary-new],[data-dictionary-edit],[data-dictionary-toggle],[data-dictionary-delete],[data-dictionary-save],[data-dictionary-delete-confirm]');if(!target)return;event.preventDefault();event.stopPropagation();if(target.dataset.dictionaryNew!==undefined)openDictionaryEditor();else if(target.dataset.dictionaryEdit)openDictionaryEditor(target.dataset.dictionaryEdit);else if(target.dataset.dictionaryToggle)toggleDictionaryEntry(target.dataset.dictionaryToggle);else if(target.dataset.dictionaryDelete)confirmDictionaryDelete(target.dataset.dictionaryDelete);else if(target.dataset.dictionarySave!==undefined)saveDictionaryForm(target.dataset.dictionarySave);else if(target.dataset.dictionaryDeleteConfirm)deleteDictionaryEntry(target.dataset.dictionaryDeleteConfirm)},true);
document.addEventListener('click',event=>{const target=event.target.closest('[data-record-save],[data-movement-history-edit],[data-movement-history-save]');if(!target)return;event.preventDefault();event.stopPropagation();if(target.dataset.recordSave!==undefined)saveRecordEdit();else if(target.dataset.movementHistoryEdit!==undefined)movementHistoryEditor(Number(target.dataset.movementHistoryEdit));else if(target.dataset.movementHistorySave!==undefined)saveMovementHistory()},true);
const quickPageBeforePlatformServices=quickPage;
quickPage=function(){
  quickPageBeforePlatformServices();
  const undoButton=$('.capture .actions .btn-light');
  if(undoButton){
    undoButton.removeAttribute('data-mock');
    undoButton.dataset.undo='';
    undoButton.textContent='Undo last save';
    api('/api/undo-status').then(status=>{
      undoButton.disabled=!status.available;
      undoButton.title=status.available?`可撤销 ${status.created_at}`:'没有可撤销记录';
    }).catch(()=>{undoButton.disabled=true});
  }
}

function issueCounts(rows){return rows.reduce((counts,item)=>{const key=String(item.severity||'').toLowerCase();counts[key]=(counts[key]||0)+1;return counts},{})}
checksPage=async function(){
  main.innerHTML='<div class="loading-page"><i></i><p>正在读取本地数据检查结果…</p></div>';
  try{
    state.dataCheck=await api('/api/data-check');
    const rows=state.dataCheck.issues||[],counts=issueCounts(rows);
    main.innerHTML=`<section class="page page-grid checks-page"><div class="content">${pageHeader('Data Check','真实扫描本地记录；Open 会直接带你到对应修正位置。')}<div class="toolbar check-filters"><button class="btn btn-primary is-selected" data-check-filter="all">全部问题 &nbsp; ${rows.length}</button><button class="btn" data-check-filter="high">高 ${counts.high||0}</button><button class="btn" data-check-filter="medium">中 ${counts.medium||0}</button><button class="btn" data-check-filter="low">低 ${counts.low||0}</button></div><div class="table-wrap check-table-wrap"><table class="check-table"><thead><tr><th>级别</th><th>日期</th><th>区域</th><th>问题</th><th>建议处理</th><th>操作</th></tr></thead><tbody>${rows.map((item,index)=>`<tr data-severity="${esc(String(item.severity).toLowerCase())}"><td><span class="severity ${esc(String(item.severity).toLowerCase())}">${esc(item.severity)}</span></td><td>${esc(item.date)}</td><td>${esc(item.area)}</td><td>${esc(item.issue)}</td><td>${esc(item.action)}</td><td><button class="link issue-open" data-real-issue="${index}">Open</button></td></tr>`).join('')}</tbody></table></div><div class="records-status" aria-live="polite">显示 ${rows.length} 个未确认问题 · 已隐藏 ${state.dataCheck.acknowledged_count||0} 个</div></div><aside class="rail"><section class="rail-section" style="margin-top:0"><span class="eyebrow">处理原则</span><h2 style="font:400 24px var(--serif)">定位、修正、再确认</h2><p>检查只提供定位，不会自动修改正式记录。</p></section><section class="rail-section"><span class="eyebrow">状态说明</span><div class="state-stack" style="margin-top:16px"><div class="state error">High · 优先核对</div><div class="state warning">Medium · 影响准确性</div><div class="state success">Low · 提示性问题</div></div></section></aside></section>`;
  }catch(error){main.innerHTML=`<div class="loading-page"><h2>Data Check unavailable</h2><p>${esc(error.message)}</p></div>`}
}

function openRealIssue(index){
  const issue=state.dataCheck?.issues?.[index];if(!issue)return;
  modal('问题详情',`<span class="severity ${esc(String(issue.severity).toLowerCase())}">${esc(issue.severity)}</span><div class="detail-list"><div class="detail-row"><label>日期</label><div>${esc(issue.date)}</div></div><div class="detail-row"><label>区域</label><div>${esc(issue.area)}</div></div><div class="detail-row"><label>具体问题</label><div>${esc(issue.issue)}</div></div><div class="detail-row"><label>建议处理</label><div>${esc(issue.action)}</div></div></div>`,{actions:`<button class="btn" data-issue-ack="${index}">确认并隐藏</button><button class="btn btn-primary" data-issue-repair="${index}">前往处理 →</button>`});
}

function repairIssue(index){
  const issue=state.dataCheck?.issues?.[index];if(!issue)return;
  root.innerHTML='';state.repairReturn=true;
  if(['body','diet','training'].includes(issue.target_type)){
    const rows={body:state.body,diet:state.diet,training:state.training}[issue.target_type]||[];
    const recordIndex=rows.findIndex(row=>String(row.id||'')===String(issue.target_id||'')||(dateOf(row)===issue.date&&!issue.target_id));
    if(recordIndex>=0){realRecordDetail(issue.target_type,recordIndex);return}
    navigate(issue.target_type);return;
  }
  if(issue.target_type==='movement'){
    const movement=state.movements.find(row=>String(row.movement_id)===String(issue.movement_id));
    if(movement){loadMovementFocus(movement.display_name);return}
    navigate('movements');return;
  }
  if(issue.target_type==='dictionary'){navigate('dictionary');return}
  if(issue.target_type==='raw'){recordDetail(issue.date);return}
  navigate(issue.area==='Diet'?'diet':issue.area==='Training'?'training':'body');
}

async function acknowledgeRealIssue(index){
  const issue=state.dataCheck?.issues?.[index];if(!issue)return;
  try{await postApi('/api/data-check/acknowledge',{issue_key:issue.issue_key});root.innerHTML='';await checksPage();showToast('该提示已确认并隐藏。')}catch(error){showToast(error.message||'确认失败。')}
}

async function undoLastWebWrite(){
  if(!window.confirm('确定撤销最近一次保存或编辑吗？\n当前数据库和动作词典会一起恢复。'))return;
  try{await postApi('/api/undo',{});await refreshWebState();navigate('quick');showToast('最近一次写入已撤销。')}catch(error){showToast(error.message||'撤销失败。')}
}

